class Brick:
    def __init__(self, x=0, y=0, z=0, rotation=0):
        self.x = x
        self.y = y
        self.z = z
        self.rotation = rotation  # 0: 0 degrees, 1: 90 degrees, etc.

    def get_studs(self):
        studs = []
        if self.rotation % 2 == 0:
            # Original orientation (2x4)
            for i in range(BRICK_WIDTH):
                for j in range(BRICK_LENGTH):
                    studs.append((self.x + i, self.y + j, self.z))
        else:
            # Rotated 90 degrees (4x2)
            for i in range(BRICK_LENGTH):
                for j in range(BRICK_WIDTH):
                    studs.append((self.x + i, self.y + j, self.z))
        return studs

    def __hash__(self):
        return hash((self.x, self.y, self.z, self.rotation))

    def __eq__(self, other):
        return (self.x, self.y, self.z, self.rotation) == (other.x, other.y, other.z, other.rotation)

def is_valid_configuration(bricks):
    # Check for overlapping studs
    all_studs = []
    for brick in bricks:
        studs = brick.get_studs()
        for stud in studs:
            if stud in all_studs:
                return False
            all_studs.append(stud)
    return True

def generate_adjacent_positions(brick, existing_bricks):
    # Generate possible adjacent positions for a new brick
    positions = []
    existing_studs = set()
    for b in existing_bricks:
        existing_studs.update(b.get_studs())

    for b in existing_bricks:
        for stud in b.get_studs():
            for dx, dy in [(0, 1), (1, 0), (0, -1), (-1, 0)]:
                new_x = stud[0] + dx
                new_y = stud[1] + dy
                new_z = stud[2]
                for rotation in [0, 1]:
                    new_brick = Brick(new_x, new_y, new_z, rotation)
                    if new_brick not in existing_bricks:
                        positions.append(new_brick)
    return positions

def count_configurations(n_bricks=6):
    if n_bricks < 1:
        return 0

    # Start with one brick at origin
    initial_brick = Brick(0, 0, 0, 0)
    configurations = set()
    configurations.add(frozenset([initial_brick]))

    for _ in range(1, n_bricks):
